import React, { useState } from 'react';
import './contactform.css';
import { useNavigate } from 'react-router-dom';

const API_BASE_URL = 'https://e-nutritionist-9bb9c8f7b2bc.herokuapp.com';
const API_LOCAL_HOST = "http://localhost:3000";

const ContactForm = ({ localHost = true }) => {
  const navigate = useNavigate();
  const API_URL = localHost ? API_LOCAL_HOST : API_BASE_URL;

  const [formData, setFormData] = useState({
    name: "",
    phone_number: "", // Change key to match backend expectations
    email: "",
    message: ""
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const response = await fetch(`${API_URL}/contact_messages`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ contact_message: formData }), // Change the key to match the backend expectations
      });

      const contentType = response.headers.get('Content-Type');
      if (contentType && contentType.includes('application/json')) {
        const result = await response.json();
        if (response.ok) {
          alert(result.message || 'Message sent successfully!');
          setFormData({
            name: "",
            phone_number: "", // Reset field name to match
            email: "",
            message: ""
          });
        } else {
          alert('There was an error sending your message: ' + (result.errors || result.error));
        }
      } else {
        console.error('Unexpected response format:', response);
        alert('Unexpected response format. Please try again later.');
      }
    } catch (error) {
      console.error('Error:', error);
      alert('There was an error sending your message.');
    }

    navigate("/thankyoumessage");
  };

  return (
    <div className="contact-form-container-outer">
      <div className="contact-form-container">
        <h2>Share anything with us</h2>
        <form className="contact-form" onSubmit={handleSubmit}>
          <label>
            Name:
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              required
            />
          </label>
          <label>
            Phone:
            <input
              type="tel"
              name="phone_number" // Change name attribute to match backend expectations
              value={formData.phone_number}
              onChange={handleChange}
              required
            />
          </label>
          <label>
            Email:
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              required
            />
          </label>
          <label>
            Message:
            <textarea
              name="message"
              value={formData.message}
              onChange={handleChange}
              required
            ></textarea>
          </label>
          <button type="submit">Submit</button>
        </form>
      </div>
    </div>
  );
};

export default ContactForm;
